  "sourcesContent": [":host {\n\tdisplay: block;\n\tposition: sticky;\n\ttop: 0;\n\tz-index: 30;\n}\n\n.site-header {\n\tdisplay: flex;\n\talign-items: center;\n\tjustify-content: space-between;\n\tgap: 1rem;\n\tpadding: 0.9rem 1.25rem;\n\tbackground: rgba(33, 25, 18, 0.9);\n\tbackdrop-filter: blur(14px);\n\tborder-bottom: 1px solid rgba(255, 225, 178, 0.2);\n\tcolor: #f7f3eb;\n}\n\n.brand {\n\tdisplay: inline-flex;\n\talign-items: center;\n\tgap: 0.85rem;\n\ttext-decoration: none;\n\tcolor: inherit;\n\twhite-space: nowrap;\n}\n\n.brand-dots {\n\tdisplay: inline-flex;\n\talign-items: center;\n\tgap: 0.25rem;\n}\n\n.dot {\n\twidth: 1.15rem;\n\theight: 1.15rem;\n\tborder-radius: 999px;\n\tdisplay: inline-block;\n}\n\n.dot-orange {\n\tbackground: #ff8f3c;\n}\n\n.dot-cyan {\n\tbackground: #ffb14c;\n}\n\n.dot-green {\n\tbackground: #f6d36b;\n}\n\n.brand-name {\n\tfont-size: 1.55rem;\n\tfont-weight: 800;\n\tletter-spacing: -0.04em;\n}\n\n.nav {\n\tdisplay: flex;\n\talign-items: center;\n\tjustify-content: center;\n\tgap: 1rem;\n\tflex: 1;\n\tmin-width: 0;\n\tflex-wrap: wrap;\n}\n\n.nav-link {\n\ttext-decoration: none;\n\tcolor: #cfbca2;\n\tfont-size: 0.88rem;\n\tfont-weight: 700;\n\tletter-spacing: 0.08em;\n\ttext-transform: uppercase;\n\tpadding: 0.3rem 0;\n\tborder-bottom: 2px solid transparent;\n}\n\n.nav-link.active {\n\tcolor: #ffd18b;\n\tborder-bottom-color: #ffb14c;\n}\n\n.actions {\n\tdisplay: flex;\n\talign-items: center;\n\tgap: 0.7rem;\n}\n\n.icon-button {\n\twidth: 2.2rem;\n\theight: 2.2rem;\n\tborder-radius: 999px;\n\tborder: 1px solid rgba(255, 225, 178, 0.22);\n\tbackground: rgba(14, 10, 7, 0.72);\n\tcolor: #f4dcc2;\n\tdisplay: grid;\n\tplace-items: center;\n\tcursor: pointer;\n\tfont-size: 1rem;\n}\n\n.avatar-link {\n\twidth: 2.5rem;\n\theight: 2.5rem;\n\tborder-radius: 999px;\n\tborder: 1px solid rgba(255, 225, 178, 0.28);\n\tbackground: linear-gradient(180deg, rgba(255, 177, 89, 0.26), rgba(255, 120, 57, 0.2));\n\tdisplay: grid;\n\tplace-items: center;\n\ttext-decoration: none;\n}\n\n.avatar-icon {\n\twidth: 1.35rem;\n\theight: 1.35rem;\n\tposition: relative;\n\tdisplay: block;\n}\n\n.avatar-icon::before,\n.avatar-icon::after {\n\tcontent: '';\n\tposition: absolute;\n\tleft: 50%;\n\ttransform: translateX(-50%);\n\tbackground: #ffd18b;\n}\n\n.avatar-icon::before {\n\ttop: 0;\n\twidth: 0.62rem;\n\theight: 0.62rem;\n\tborder-radius: 999px;\n}\n\n.avatar-icon::after {\n\tbottom: 0;\n\twidth: 1.2rem;\n\theight: 0.7rem;\n\tborder-radius: 0.7rem 0.7rem 0.2rem 0.2rem;\n}\n\n@media (max-width: 720px) {\n\t.site-header {\n\t\tpadding: 0.75rem 0.85rem;\n\t\tgap: 0.6rem;\n\t\talign-items: center;\n\t\tflex-wrap: wrap;\n\t}\n\n\t.brand {\n\t\tgap: 0.6rem;\n\t\tmin-width: 0;\n\t}\n\n\t.brand-dots {\n\t\tgap: 0.18rem;\n\t}\n\n\t.dot {\n\t\twidth: 0.9rem;\n\t\theight: 0.9rem;\n\t}\n\n\t.brand-name {\n\t\tfont-size: 1.12rem;\n\t\tline-height: 1;\n\t}\n\n\t.nav {\n\t\torder: 3;\n\t\tjustify-content: flex-start;\n\t\toverflow-x: auto;\n\t\tpadding: 0.15rem 0 0.05rem;\n\t\tgap: 0.55rem;\n\t\tflex-basis: 100%;\n\t\tscrollbar-width: none;\n\t}\n\n\t.nav-link {\n\t\tfont-size: 0.76rem;\n\t\tpadding: 0.2rem 0;\n\t\tletter-spacing: 0.06em;\n\t\twhite-space: nowrap;\n\t}\n\n\t.actions {\n\t\tmargin-left: auto;\n\t\tgap: 0.45rem;\n\t}\n\n\t.icon-button {\n\t\twidth: 2.1rem;\n\t\theight: 2.1rem;\n\t\tfont-size: 0.95rem;\n\t}\n\n\t.avatar-link {\n\t\twidth: 2.2rem;\n\t\theight: 2.2rem;\n\t}\n\n\t.avatar-icon {\n\t\twidth: 1.1rem;\n\t\theight: 1.1rem;\n\t}\n\n\t.avatar-icon::before {\n\t\twidth: 0.52rem;\n\t\theight: 0.52rem;\n\t}\n\n\t.avatar-icon::after {\n\t\twidth: 0.95rem;\n\t\theight: 0.55rem;\n\t}\n\n\t.nav::-webkit-scrollbar {\n\t\tdisplay: none;\n\t}\n\n\t.actions {\n\t\tmargin-left: auto;\n\t}\n\n\t.brand-name {\n\t\tfont-size: 1.1rem;\n\t}\n\n\t.site-header {\n\t\talign-items: center;\n\t}\n\n\t.nav {\n\t\tpadding-bottom: 0.05rem;\n\t\tscrollbar-width: none;\n\t}\n}\n\n@media (max-width: 480px) {\n\t.site-header {\n\t\tpadding: 0.7rem 0.75rem;\n\t\tgap: 0.45rem;\n\t}\n\n\t.brand {\n\t\tgap: 0.5rem;\n\t}\n\n\t.brand-name {\n\t\tfont-size: 1rem;\n\t\tmax-width: 9.5rem;\n\t\toverflow: hidden;\n\t\ttext-overflow: ellipsis;\n\t}\n\n\t.nav {\n\t\tgap: 0.45rem;\n\t}\n\n\t.nav-link {\n\t\tfont-size: 0.72rem;\n\t}\n\n\t.actions {\n\t\tgap: 0.35rem;\n\t}\n\n\t.icon-button,\n\t.avatar-link {\n\t\twidth: 2rem;\n\t\theight: 2rem;\n\t}\n\n\t.avatar-icon {\n\t\twidth: 1rem;\n\t\theight: 1rem;\n\t}\n\n\t.avatar-icon::before {\n\t\twidth: 0.46rem;\n\t\theight: 0.46rem;\n\t}\n\n\t.avatar-icon::after {\n\t\twidth: 0.84rem;\n\t\theight: 0.5rem;\n\t}\n}"],
